const qrCode = `BUS-${Date.now()}-TEST`;
const deepLink = `smartbusapp://simulate?type=qr&code=${qrCode}`;

node.warn(`📱 Open this link on your device/emulator:\n${deepLink}`);
node.warn(`📋 Or scan this QR code: ${qrCode}`);

msg.payload = {
    qr_code: qrCode,
    deep_link: deepLink,
    instruction: "Copy link and open in browser, or use 'adb shell am start -a android.intent.action.VIEW -d deepLink' on emulator"
};

return msg;

// Harare coordinates
const lat = -17.8292;
const lng = 31.0522;
const deepLink = `smartbusapp://simulate?type=gps&lat=${lat}&lng=${lng}`;

node.warn(`📱 GPS Deep Link:\n${deepLink}`);

msg.payload = {
    latitude: lat,
    longitude: lng,
    deep_link: deepLink,
    instruction: "This will set app GPS to Harare"
};

return msg;

const destination = "Harare";
const distance = 500; // meters
const deepLink = `smartbusapp://simulate?type=approaching&destination=${destination}&distance=${distance}`;

node.warn(`📱 Approaching Alert Link:\n${deepLink}`);

msg.payload = {
    destination: destination,
    distance: distance,
    deep_link: deepLink,
    instruction: "Triggers 'Approaching Destination' alert in app"
};

return msg;

const destination = "Harare";
const deepLink = `smartbusapp://simulate?type=missed&destination=${destination}`;

node.warn(`📱 Missed Destination Link:\n${deepLink}`);

msg.payload = {
    destination: destination,
    deep_link: deepLink,
    instruction: "Triggers 'Missed Destination' alert in app"
};

return msg;

// Simulate journey from Bulawayo to near Harare
// Creating waypoints every ~40km
const waypoints = [
    {lat: -20.1500, lng: 28.5667, heading: 45, speed: 22},  // Bulawayo (start)
    {lat: -19.8000, lng: 28.8000, heading: 45, speed: 25},  // 40km NE
    {lat: -19.4500, lng: 29.0500, heading: 45, speed: 24},  // 80km NE
    {lat: -19.1000, lng: 29.3000, heading: 50, speed: 23},  // 120km NE
    {lat: -18.7500, lng: 29.6000, heading: 55, speed: 25},  // 160km NE
    {lat: -18.4000, lng: 29.9000, heading: 60, speed: 22},  // 200km NE
    {lat: -18.1000, lng: 30.2500, heading: 65, speed: 20},  // 240km NE (approaching)
    {lat: -17.9000, lng: 30.6000, heading: 70, speed: 18},  // 280km NE (closer)
    {lat: -17.8500, lng: 30.8500, heading: 75, speed: 15},  // Near Harare (500m away)
    {lat: -17.8292, lng: 31.0522, heading: 80, speed: 10}   // Harare (destination)
];

const sessionId = `journey-${Date.now()}`;
flow.set('currentSessionId', sessionId);

msg.payload = {
    session_id: sessionId,
    name: "Bulawayo to Harare",
    description: "Simulated highway journey with approaching and arrival alerts",
    waypoints: waypoints
};

node.status({fill:"blue", shape:"dot", text:`Session: ${sessionId}`});
node.warn(`🗺️ Created ${waypoints.length} waypoints for journey`);

return msg;

const sessionId = flow.get('currentSessionId');

if (!sessionId) {
    node.error("No session found! Create journey first.");
    return null;
}

const deepLink = `smartbusapp://simulate/gps?session_id=${sessionId}`;

node.warn(`📱 START JOURNEY:\n${deepLink}\n\nFor Android Emulator, run in terminal:\nadb shell am start -a android.intent.action.VIEW -d "${deepLink}"`);

msg.payload = {
    session_id: sessionId,
    deep_link: deepLink,
    adb_command: `adb shell am start -a android.intent.action.VIEW -d "${deepLink}"`,
    instruction: "Copy the adb command and run it in your terminal, or open the deep link on your device"
};

return msg;

// Step 1: Create a trip
const timestamp = Date.now();
const qrCode = `BUS-${timestamp}-SCENARIO`;

msg.tripData = {
    phone_number: "+263771234567",
    origin_lat: -20.1500,
    origin_lng: 28.5667,
    destination_name: "Harare",
    destination_lat: -17.8292,
    destination_lng: 31.0522,
    distance_km: 439.2,
    fare: 15.0,
    qr_code: qrCode
};

flow.set('scenarioQR', qrCode);
flow.set('scenarioSessionId', `scenario-${timestamp}`);

msg.payload = msg.tripData;
node.warn(`🎬 Starting complete scenario with QR: ${qrCode}`);

return msg;

const qrCode = flow.get('scenarioQR');
const sessionId = flow.get('scenarioSessionId');

// Generate all deep links
const qrLink = `smartbusapp://simulate?type=qr&code=${qrCode}`;
const startJourneyLink = `smartbusapp://simulate/gps?session_id=${sessionId}`;

node.warn(`\n🎬 COMPLETE SCENARIO READY!\n\n` +
    `1️⃣ Scan QR Code:\n   ${qrLink}\n\n` +
    `2️⃣ Start GPS Journey:\n   ${startJourneyLink}\n\n` +
    `📱 For Android Emulator:\n   adb shell am start -a android.intent.action.VIEW -d "${qrLink}"\n   adb shell am start -a android.intent.action.VIEW -d "${startJourneyLink}"\n`);

msg.payload = {
    success: true,
    qr_code: qrCode,
    session_id: sessionId,
    qr_link: qrLink,
    journey_link: startJourneyLink,
    adb_qr: `adb shell am start -a android.intent.action.VIEW -d "${qrLink}"`,
    adb_journey: `adb shell am start -a android.intent.action.VIEW -d "${startJourneyLink}"`,
    instructions: [
        "1. Run the adb_qr command to simulate QR scan",
        "2. Run the adb_journey command to start GPS simulation",
        "3. Watch the app respond to GPS updates with alerts"
    ]
};

return msg;
